#include<iostream>#include<cmath>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;     cin>>t;    while(t--){        ll a,b;        cin>>a>>b;        ll ra=a;//to get odd part of a and b        ll rb=b;        while(ra%2==0){            ra/=2;        }        while(rb%2==0){            rb/=2;        }        if(ra!=rb){            cout<<-1<<"\n";        }        else{            a= a/ra;            b= b/rb;            a= log2(a);            b= log2(b);            cout<<ceil(abs(a-b)/3.0)<<"\n";        }    }}